PROXY_PORT=32815
NS=elasticsearch

# Step 1: Update index settings to allow shards on all nodes and set replicas to 0
curl -s -X PUT "http://127.0.0.1:${PROXY_PORT}/api/v1/namespaces/${NS}/services/es-http:9200/proxy/app-data/_settings" \
  -H "Content-Type: application/json" \
  -d '{
    "index": {
      "number_of_replicas": 0,
      "routing": {
        "allocation": {
          "include": {
            "_name": ""
          }
        }
      }
    }
  }' 2>&1

PROXY_PORT=32815
NS=elasticsearch

# Step 2: Exclude es-cluster-1 and es-cluster-2 from allocation to force shards to es-cluster-0
curl -s -X PUT "http://127.0.0.1:${PROXY_PORT}/api/v1/namespaces/${NS}/services/es-http:9200/proxy/_cluster/settings" \
  -H "Content-Type: application/json" \
  -d '{
    "transient": {
      "cluster.routing.allocation.exclude._name": "es-cluster-1,es-cluster-2"
    }
  }' 2>&1

